class Solution:
    def minimumRefill(self, plants, capacityA, capacityB):
        """
        :type plants: List[int]
        :type capacityA: int
        :type capacityB: int
        :rtype: int
        """
        refills = 0
        waterA, waterB = capacityA, capacityB
        left, right = 0, len(plants) - 1

        while left <= right:
            if left == right:
                # Same plant: whoever has more water waters it
                if waterA >= waterB:
                    if waterA < plants[left]:
                        refills += 1
                else:
                    if waterB < plants[left]:
                        refills += 1
                break

            # Alice waters left
            if waterA >= plants[left]:
                waterA -= plants[left]
            else:
                refills += 1
                waterA = capacityA - plants[left]

            left += 1

            # Bob waters right
            if waterB >= plants[right]:
                waterB -= plants[right]
            else:
                refills += 1
                waterB = capacityB - plants[right]

            right -= 1

        return refills
